-- ============================================================================
-- Migration: Create chassis_master table and import all 769 chassis
-- Description: Real chassis data from MCL_8-14-25.xlsx (Forrest LTL & Owned)
-- ============================================================================

CREATE TABLE IF NOT EXISTS chassis_master (
  chassis_number              TEXT PRIMARY KEY,
  old_chassis_number          TEXT,
  under_frqt_in_gier          TEXT,
  chassis_status              TEXT NOT NULL,
  chassis_category            TEXT,
  chassis_reporting_category  TEXT,
  lessor                      TEXT,
  description                 TEXT,
  chassis_type                TEXT,
  region                      TEXT,
  charge_code_in_mg           TEXT,
  serial_number               TEXT,
  plate_number                TEXT,
  plate_state                 TEXT,
  manufacturer                TEXT,
  model_year                  INTEGER,
  tare_weight                 TEXT,
  original_stated_value       NUMERIC(12,2),
  pickup_location             TEXT,
  pickup_handling_fee         NUMERIC(10,2),
  return_handling_fee         NUMERIC(10,2),
  contract_number             TEXT,
  contract_status             TEXT,
  date_last_contract_signed   DATE,
  initial_lease_term          TEXT,
  initial_lease_start         DATE,
  initial_lease_end           DATE,
  current_lease_term          TEXT,
  extended_lease_term         TEXT,
  extended_lease_start        DATE,
  extended_lease_end          DATE,
  auto_renew_1_start          DATE,
  auto_renew_1_end            DATE,
  auto_renew_2_start          DATE,
  auto_renew_2_end            DATE,
  on_hire_date                DATE,
  off_hire_date               DATE,
  notice_90day_expiration     DATE,
  initial_lease_rate          NUMERIC(8,4),
  initial_gps_rate            NUMERIC(8,4),
  initial_total_rate          NUMERIC(8,4),
  extended_lease_rate         NUMERIC(8,4),
  extended_gps_rate           NUMERIC(8,4),
  extended_total_rate         NUMERIC(8,4),
  current_rate_per_day        NUMERIC(8,4),
  gps_provider                TEXT,
  hard_gps_number             TEXT,
  anytrek_unit_number         TEXT,
  contract_end_date           DATE,
  notes                       TEXT,
  created_at                  TIMESTAMPTZ DEFAULT now(),
  updated_at                  TIMESTAMPTZ DEFAULT now()
);

-- Indexes
CREATE INDEX IF NOT EXISTS idx_chassis_master_status   ON chassis_master(chassis_status);
CREATE INDEX IF NOT EXISTS idx_chassis_master_lessor   ON chassis_master(lessor);
CREATE INDEX IF NOT EXISTS idx_chassis_master_gps      ON chassis_master(gps_provider);
CREATE INDEX IF NOT EXISTS idx_chassis_master_region   ON chassis_master(region);
CREATE INDEX IF NOT EXISTS idx_chassis_master_type     ON chassis_master(chassis_type);

-- Auto-update updated_at
DROP TRIGGER IF EXISTS set_updated_at ON chassis_master;
CREATE TRIGGER set_updated_at
  BEFORE UPDATE ON chassis_master
  FOR EACH ROW EXECUTE FUNCTION update_updated_at_column();

-- RLS
ALTER TABLE chassis_master ENABLE ROW LEVEL SECURITY;
CREATE POLICY "Authenticated read"   ON chassis_master FOR SELECT TO authenticated USING (true);
CREATE POLICY "Authenticated write"  ON chassis_master FOR INSERT TO authenticated WITH CHECK (true);
CREATE POLICY "Authenticated update" ON chassis_master FOR UPDATE TO authenticated USING (true) WITH CHECK (true);
CREATE POLICY "Authenticated delete" ON chassis_master FOR DELETE TO authenticated USING (true);

